const order = $json;
const prev = $('Apply Delivery State').first().json;
const cart = prev.context_json?.cart || [];

return cart.map(item => ({
  json: {
    order_id: order.id,
    item_code: item.item_code,
    item_name: item.item_name,
    quantity: item.quantity,
    unit_price: item.unit_price,
    line_subtotal: item.line_subtotal,
    configuration: item.configuration || null,
    extras: item.extras || []
  }
}));

const prev = $('Apply Delivery State').first().json;
const ctx = prev.context_json ?? {};
const cart = Array.isArray(ctx.cart) ? ctx.cart : [];

const subtotal = Number(
  cart.reduce((sum, item) => sum + Number(item.line_subtotal || 0), 0).toFixed(2)
);

const deliveryFee = 10.00;
const total = Number((subtotal + deliveryFee).toFixed(2));

ctx.delivery = ctx.delivery ?? {};
ctx.delivery.zone_id = null;
ctx.delivery.delivery_fee = deliveryFee;
ctx.delivery.eta_min = 45;
ctx.delivery.eta_max = 60;

ctx.flow = 'delivery';
ctx.step = 'awaiting_order_confirmation';
ctx.intent = 'delivery_order';

const lines = cart.map(item =>
  `- ${item.quantity} x ${item.item_name} — S/ ${Number(item.line_subtotal).toFixed(2)}`
);

const reply = `Perfecto, este es el resumen de tu pedido:

${lines.join('\n')}

Subtotal: S/ ${subtotal.toFixed(2)}
Delivery: S/ ${deliveryFee.toFixed(2)}
Total: S/ ${total.toFixed(2)}

Dirección: ${ctx.delivery.address_text || '-'}
Referencia: ${ctx.delivery.reference_text || '-'}
Zona/Distrito: ${ctx.delivery.district || '-'}

Tiempo estimado: ${ctx.delivery.eta_min} a ${ctx.delivery.eta_max} min

¿Deseas confirmar tu pedido? Puedes responder: sí o no.`;

return [
  {
    json: {
      ...prev,
      reply_text: reply,
      new_flow: 'delivery',
      new_step: 'awaiting_order_confirmation',
      context_json: ctx,
      order_summary: {
        subtotal,
        delivery_fee: deliveryFee,
        total
      }
    }
  }
];

const ctx = $json.context_json ?? {};
const cart = Array.isArray(ctx.cart) ? ctx.cart : [];

const subtotal = Number(
  cart.reduce((sum, item) => sum + Number(item.line_subtotal || 0), 0).toFixed(2)
);

const total = subtotal;

ctx.flow = 'delivery';
ctx.step = 'awaiting_order_confirmation';
ctx.intent = 'delivery_order';

const lines = cart.map(item =>
  `- ${item.quantity} x ${item.item_name} — S/ ${Number(item.line_subtotal).toFixed(2)}`
);

const reply = `Perfecto, este es el resumen de tu pedido para recojo en tienda:

${lines.join('\n')}

Subtotal: S/ ${subtotal.toFixed(2)}
Delivery: S/ 0.00
Total: S/ ${total.toFixed(2)}

Modalidad: Recojo en tienda
Nombre: ${ctx.customer?.name || '-'}
Teléfono: ${ctx.customer?.phone || '-'}

¿Deseas confirmar tu pedido? Puedes responder: sí o no.`;

return [
  {
    json: {
      ...$json,
      reply_text: reply,
      new_flow: 'delivery',
      new_step: 'awaiting_order_confirmation',
      context_json: ctx,
      order_summary: {
        subtotal,
        delivery_fee: 0,
        total
      }
    }
  }
];

const prev = $('Apply Delivery State').first().json;
const resolution = $json || {};

const ctx = prev.context_json ?? {};
const cart = Array.isArray(ctx.cart) ? ctx.cart : [];

const subtotal = Number(
  cart.reduce((sum, item) => sum + Number(item.line_subtotal || 0), 0).toFixed(2)
);

// Extraer info del motor de scoring
const status = resolution.coverage_status || 'unknown';
const deliveryFee = Number(resolution.delivery_fee || 0);
const confidence = Number(resolution.confidence_score || 0);
const etaMin = resolution.eta_min ?? 45;
const etaMax = resolution.eta_max ?? 60;
const zoneId = resolution.zone_id ?? null;

ctx.delivery = ctx.delivery ?? {};
ctx.delivery.zone_id = zoneId;
ctx.delivery.delivery_fee = deliveryFee;
ctx.delivery.eta_min = etaMin;
ctx.delivery.eta_max = etaMax;
ctx.delivery.coverage_status = status;
ctx.delivery.delivery_confidence = confidence;
ctx.delivery.delivery_resolution_method = resolution.resolution_method || 'hybrid_resolution_v2';
ctx.delivery.delivery_resolution_detail = {
  matched_keywords: resolution.matched_keywords || [],
  district_match: resolution.district_match || false,
  resolution_method: resolution.resolution_method || 'hybrid_resolution_v2'
};

let reply = '';
let nextStep = 'awaiting_order_confirmation';

// --- LOGICA FAIL FAST ---

if (status === 'out_of_coverage') {
  // Caso 1: Fuera de cobertura detectado inmediatamente
  reply = `Lo siento, parece que tu ubicación está fuera de nuestra zona de cobertura actual. 😔\n\n¿Deseas cambiar el pedido a **Recojo en Tienda** para continuar?`;
  nextStep = 'awaiting_fulfillment_type';
  ctx.delivery.fulfillment_type = null; // Reiniciar para que elija de nuevo
} else if (!ctx.delivery.address_text) {
  // Caso 2: Cubierto o insuficiente pero falta la dirección
  reply = `¡Genial! Sí llegamos a esa zona. 🚚 Ahora compárteme la dirección exacta de entrega por favor.`;
  nextStep = 'awaiting_address';
} else if (!ctx.delivery.district) {
  // Caso 3: Cubierto o insuficiente pero falta el distrito (raro si llegamos aquí, pero por precaución)
  reply = `Perfecto. Para ser exactos, ¿en qué distrito o zona te encuentras?`;
  nextStep = 'awaiting_district';
} else if (status === 'insufficient_data' && confidence < 70 && !ctx.delivery.reference_text) {
  // Caso 4: Tenemos dirección y zona pero no hay confianza suficiente, pedir referencia
  reply = `No pude cobrarte el delivery con exactitud. 🤔\n\n¿Podrías darme una referencia más precisa de tu ubicación? (Ej: "Frente al parque", "Al costado de la botica").`;
  nextStep = 'awaiting_reference';
} else {
  // Caso 5: Todo completo o datos suficientes para cobrar
  const total = Number((subtotal + deliveryFee).toFixed(2));
  const lines = cart.map(item =>
    `- ${item.quantity} x ${item.item_name} — S/ ${Number(item.line_subtotal).toFixed(2)}`
  );

  reply = `Perfecto, este es el resumen de tu pedido:\n\n${lines.join('\n')}\n\nSubtotal: S/ ${subtotal.toFixed(2)}\nDelivery: S/ ${deliveryFee.toFixed(2)}\nTotal: S/ ${total.toFixed(2)}\n\nDirección: ${ctx.delivery.address_text || '-'}\nReferencia: ${ctx.delivery.reference_text || '-'}\nZona/Distrito: ${ctx.delivery.district || '-'}\n\nTiempo estimado: ${etaMin} a ${etaMax} min\n\n¿Deseas confirmar tu pedido? Puedes responder: sí o no.`;
  nextStep = 'awaiting_order_confirmation';
}

ctx.flow = 'delivery';
ctx.step = nextStep;

return [
  {
    json: {
      ...prev,
      reply_text: reply,
      new_flow: 'delivery',
      new_step: nextStep,
      context_json: ctx,
      order_summary: {
        subtotal,
        delivery_fee: deliveryFee,
        total: Number((subtotal + deliveryFee).toFixed(2))
      }
    }
  }
];

const original = $("Apply Delivery State").first().json;
const ctx = original.context_json ?? {};

const preservedCustomer = ctx.customer ?? {};
const preservedEventRequest = ctx.event_request ?? {};
const fulfillmentType = ctx.delivery?.fulfillment_type || "delivery";

const cleanedCtx = {
  cart: [],
  flow: "delivery",
  step: "completed",
  intent: "delivery_order",
  customer: preservedCustomer,
  delivery: {
    fulfillment_type: fulfillmentType,
    eta_max: null,
    eta_min: null,
    zone_id: null,
    district: null,
    address_text: null,
    delivery_fee: null,
    reference_text: null,
  },
  event_request: preservedEventRequest,
  last_menu_shown_at: ctx.last_menu_shown_at ?? null,
  last_summary_shown_at: new Date().toISOString(),
};

return [
  {
    json: {
      ...original,
      new_flow: "delivery",
      new_step: "completed",
      context_json: cleanedCtx,
    },
  },
];

const original = $('When Executed by Another Workflow').first().json || {};
const ctx = original.context_json ?? {};
const cart = Array.isArray(ctx.cart) ? ctx.cart : [];
const customer = ctx.customer ?? {};
const delivery = ctx.delivery ?? {};

let menuItems = [];

try {
  const fromNode = $('Load Active Menu').all();
  if (Array.isArray(fromNode) && fromNode.length > 0) {
    menuItems = fromNode.map(i => {
      const r = i.json ?? {};
      return {
        id: r.id ?? null,
        code: r.code ?? null,
        name: r.name ?? null,
        base_price: Number(r.base_price ?? r.price ?? 0),
        is_active: r.is_active ?? true
      };
    });
  }
} catch (e) {
  menuItems = [];
}

return [
  {
    json: {
      intent: original.intent ?? null,
      confidence: original.confidence ?? null,
      entities: original.entities ?? {},
      channel: original.channel ?? null,
      conversation_id: original.conversation_id ?? null,
      customer_id: original.customer_id ?? null,
      customer_name: original.customer_name ?? null,
      telegram_chat_id: original.telegram_chat_id ?? null,

      current_flow: original.current_flow ?? ctx.flow ?? 'delivery',
      current_step: original.current_step ?? ctx.step ?? 'awaiting_order_items',
      message_text: String(original.message_text ?? '').trim(),

      lat: original.lat ?? null,
      lng: original.lng ?? null,
      location_shared_at: original.location_shared_at ?? null,

      context_json: ctx,
      cart,
      customer,
      delivery,
      menu_items: menuItems,

      cart_count: cart.length,
      cart_subtotal: Number(
        cart.reduce((sum, item) => sum + Number(item.line_subtotal ?? 0), 0).toFixed(2)
      )
    }
  }
];

const original = $('Build Delivery Interpreter Input').first().json;
const parsed = $('Parse Delivery Interpreter JSON').first().json;

const ctx = original.context_json ?? {};

return [
  {
    json: {
      ...original,
      reply_text:
        parsed.answer_to_user ||
        'Claro, te ayudo con esa duda. Luego continuamos con tu pedido.',
      new_flow: original.current_flow || 'delivery',
      new_step: original.current_step || 'awaiting_order_items',
      context_json: ctx
    }
  }
];

const original = $('Build Delivery Interpreter Input').first().json;
const parsed = $('Parse Delivery Interpreter JSON').first().json;

const ctx = original.context_json ?? {};

return [
  {
    json: {
      ...original,
      reply_text:
        parsed.answer_to_user ||
        'Entendido. Puedo ayudarte con delivery, carta o eventos. Indícame qué deseas hacer.',
      new_flow: original.current_flow || 'delivery',
      new_step: original.current_step || 'awaiting_order_items',
      context_json: ctx
    }
  }
];

const original = $('Build Delivery Interpreter Input').first().json;
const parsed = $('Parse Delivery Interpreter JSON').first().json;

const ctx = original.context_json ?? {};
const step = original.current_step || 'awaiting_order_items';

function reprompt(stepName) {
  switch (stepName) {
    case 'awaiting_order_items':
      return 'Indícame qué deseas pedir. Por ejemplo: "2 chaufas de pollo y una gaseosa".';
    case 'awaiting_post_cart_decision':
      return 'Indícame si deseas agregar algo más o si continuamos con tus datos.';
    case 'awaiting_customer_name':
      return 'Por favor indícame el nombre para registrar tu pedido.';
    case 'awaiting_customer_phone':
      return 'Por favor compárteme un número de celular válido de 9 dígitos.';
    case 'awaiting_fulfillment_type':
      return 'Indícame si tu pedido es para delivery o para recojo en tienda.';
    case 'awaiting_address':
      return 'Compárteme la dirección de entrega.';
    case 'awaiting_reference':
      return 'Indícame una referencia para ubicar mejor la dirección.';
    case 'awaiting_district':
      return 'Indícame tu distrito o zona para calcular el delivery.';
    case 'awaiting_order_confirmation':
      return 'Respóndeme si deseas confirmar el pedido con un "sí" o "no".';
    default:
      return 'No logré entenderte bien. ¿Podrías decírmelo de otra forma?';
  }
}

return [
  {
    json: {
      ...original,
      reply_text: parsed.answer_to_user || reprompt(step),
      new_flow: original.current_flow || 'delivery',
      new_step: step,
      context_json: ctx
    }
  }
];

const original = $('Build Delivery Interpreter Input').first().json;
const parsed = $('Parse Delivery Interpreter JSON').first().json;

const ctx = original.context_json ?? {};
ctx.cart = Array.isArray(ctx.cart) ? ctx.cart : [];
ctx.customer = ctx.customer ?? {};
ctx.delivery = ctx.delivery ?? {};

const currentStep = original.current_step || 'awaiting_order_items';
const userGoal = parsed.user_goal || 'unknown';
const extracted = parsed.extracted ?? {};
const items = Array.isArray(extracted.items) ? extracted.items : [];

function cartSubtotal(cart) {
  return Number(
    cart.reduce((sum, item) => sum + Number(item.line_subtotal || 0), 0).toFixed(2)
  );
}

function normalizePhone(phone) {
  return String(phone || '').replace(/\D/g, '');
}

function clone(obj) {
  return JSON.parse(JSON.stringify(obj));
}

let nextCtx = clone(ctx);
const lat = original.lat ?? null;
const lng = original.lng ?? null;
const locationSharedAt = original.location_shared_at ?? null;

if (lat && lng) {
  nextCtx.delivery.lat = lat;
  nextCtx.delivery.lng = lng;
  nextCtx.delivery.location_source = 'telegram_location';
  nextCtx.delivery.location_shared_at = locationSharedAt;
}

let replyText = parsed.answer_to_user || null;
let newStep = currentStep;
let applyAction = 'reply_now';
let orderSummary = null;

function goToCheckout() {
  if (!nextCtx.customer.name) {
    nextCtx.step = 'awaiting_customer_name';
    return {
      step: 'awaiting_customer_name',
      reply: 'Perfecto. Indícame el nombre para registrar tu pedido.'
    };
  }

  if (!nextCtx.customer.phone) {
    nextCtx.step = 'awaiting_customer_phone';
    return {
      step: 'awaiting_customer_phone',
      reply: `Gracias, ${nextCtx.customer.name}. ¿Cuál es tu número de celular para coordinar tu pedido?`
    };
  }

  nextCtx.step = 'awaiting_fulfillment_type';
  return {
    step: 'awaiting_fulfillment_type',
    reply: 'Gracias. ¿Tu pedido es para delivery o para recojo en tienda?'
  };
}

switch (userGoal) {
  case 'start_order':
  case 'ask_menu': {
    nextCtx.flow = 'delivery';
    nextCtx.step = 'awaiting_order_items';
    nextCtx.intent = 'delivery_order';

    replyText =
      replyText ||
      'Perfecto. Indícame qué deseas pedir. Por ejemplo: "2 chaufas de pollo y una gaseosa".';

    newStep = 'awaiting_order_items';
    applyAction = (nextCtx.delivery.district || nextCtx.delivery.lat) ? 'calculate_delivery' : 'reply_now';
    break;
  }

  case 'add_items': {
    const validItems = items.filter(i => i.product_code && i.product_name);

    if (validItems.length === 0) {
      nextCtx.flow = 'delivery';
      nextCtx.step = currentStep === 'awaiting_post_cart_decision'
        ? 'awaiting_post_cart_decision'
        : 'awaiting_order_items';
      nextCtx.intent = 'delivery_order';

      replyText =
        replyText ||
        'No pude identificar con claridad los productos. Indícame qué deseas pedir, por ejemplo: "1 chaufa de pollo y 1 gaseosa".';

      newStep = nextCtx.step;
      applyAction = 'reply_now';
      break;
    }

    const missingQty = validItems.filter(i => !Number.isInteger(i.quantity) || i.quantity <= 0);

    if (missingQty.length > 0) {
      nextCtx.flow = 'delivery';
      nextCtx.step = 'awaiting_order_items';
      nextCtx.intent = 'delivery_order';

      const names = missingQty.map(i => i.product_name).join(', ');
      replyText =
        replyText ||
        `Indícame la cantidad para: ${names}. Por ejemplo: 1 o 2 unidades.`;

      newStep = 'awaiting_order_items';
      applyAction = 'reply_now';
      break;
    }

    for (const item of validItems) {
      const qty = Number(item.quantity);
      const unitPrice = Number(item.unit_price || 0);
      const lineSubtotal = Number((qty * unitPrice).toFixed(2));

      nextCtx.cart.push({
        item_code: item.product_code,
        item_name: item.product_name,
        quantity: qty,
        unit_price: unitPrice,
        line_subtotal: lineSubtotal,
        configuration: null,
        extras: []
      });
    }

    nextCtx.flow = 'delivery';
    nextCtx.step = 'awaiting_post_cart_decision';
    nextCtx.intent = 'delivery_order';

    const addedText = validItems.map(i => `${i.quantity} x ${i.product_name}`).join(', ');

    replyText =
      replyText ||
      `Perfecto, agregué ${addedText} a tu pedido. ¿Deseas agregar algo más o continuamos con tus datos?`;

    newStep = 'awaiting_post_cart_decision';
    applyAction = 'reply_now';
    break;
  }

  case 'continue_checkout': {
    nextCtx.flow = 'delivery';
    nextCtx.intent = 'delivery_order';

    if (!Array.isArray(nextCtx.cart) || nextCtx.cart.length === 0) {
      nextCtx.step = 'awaiting_order_items';
      replyText =
        replyText ||
        'Aún no tengo productos en tu pedido. Indícame qué deseas pedir.';
      newStep = 'awaiting_order_items';
      applyAction = 'reply_now';
      break;
    }

    const next = goToCheckout();
    replyText = replyText || next.reply;
    newStep = next.step;
    applyAction = 'reply_now';
    break;
  }

  case 'remove_items':
  case 'modify_order': {
    nextCtx.flow = 'delivery';
    nextCtx.step = 'awaiting_post_cart_decision';
    nextCtx.intent = 'delivery_order';

    replyText =
      replyText ||
      'Entendido. Indícame exactamente qué producto deseas quitar o cambiar en tu pedido.';

    newStep = 'awaiting_post_cart_decision';
    applyAction = 'reply_now';
    break;
  }

  case 'provide_name': {
    const name = extracted.customer_name ? String(extracted.customer_name).trim() : null;
    const phone = extracted.customer_phone ? normalizePhone(extracted.customer_phone) : null;

    if (name) nextCtx.customer.name = name;
    if (phone && /^\d{9}$/.test(phone)) nextCtx.customer.phone = phone;

    nextCtx.flow = 'delivery';
    nextCtx.intent = 'delivery_order';

    if (!nextCtx.customer.name) {
      nextCtx.step = 'awaiting_customer_name';
      replyText = replyText || 'Por favor indícame el nombre para registrar tu pedido.';
      newStep = 'awaiting_customer_name';
      applyAction = 'reply_now';
      break;
    }

    if (!nextCtx.customer.phone) {
      nextCtx.step = 'awaiting_customer_phone';
      replyText =
        replyText ||
        `Gracias, ${nextCtx.customer.name}. ¿Cuál es tu número de celular para coordinar tu pedido?`;
      newStep = 'awaiting_customer_phone';
      applyAction = 'reply_now';
      break;
    }

    nextCtx.step = 'awaiting_fulfillment_type';
    replyText =
      replyText ||
      `Gracias, ${nextCtx.customer.name}. ¿Tu pedido es para delivery o para recojo en tienda?`;
    newStep = 'awaiting_fulfillment_type';
    applyAction = 'reply_now';
    break;
  }

  case 'provide_phone': {
    const phone = normalizePhone(extracted.customer_phone);

    nextCtx.flow = 'delivery';
    nextCtx.intent = 'delivery_order';

    if (!/^\d{9}$/.test(phone)) {
      nextCtx.step = 'awaiting_customer_phone';
      replyText =
        replyText ||
        'Por favor compárteme un número de celular válido de 9 dígitos.';
      newStep = 'awaiting_customer_phone';
      applyAction = 'reply_now';
      break;
    }

    nextCtx.customer.phone = phone;

    if (!nextCtx.customer.name) {
      nextCtx.step = 'awaiting_customer_name';
      replyText =
        replyText ||
        'Perfecto. Ahora indícame el nombre para registrar tu pedido.';
      newStep = 'awaiting_customer_name';
      applyAction = 'reply_now';
      break;
    }

    nextCtx.step = 'awaiting_fulfillment_type';
    replyText =
      replyText ||
      'Gracias. ¿Tu pedido es para delivery o para recojo en tienda?';
    newStep = 'awaiting_fulfillment_type';
    applyAction = 'reply_now';
    break;
  }

  case 'choose_fulfillment': {
    const fulfillment = extracted.fulfillment_type;

    nextCtx.flow = 'delivery';
    nextCtx.intent = 'delivery_order';

    if (!fulfillment || !['delivery', 'pickup'].includes(fulfillment)) {
      nextCtx.step = 'awaiting_fulfillment_type';
      replyText =
        replyText ||
        'Indícame si tu pedido es para delivery o para recojo en tienda.';
      newStep = 'awaiting_fulfillment_type';
      applyAction = 'reply_now';
      break;
    }

    nextCtx.delivery.fulfillment_type = fulfillment;

    if (fulfillment === 'pickup') {
      nextCtx.delivery.delivery_fee = 0;
      nextCtx.delivery.eta_min = null;
      nextCtx.delivery.eta_max = null;
      nextCtx.delivery.zone_id = null;
      nextCtx.delivery.district = null;
      nextCtx.delivery.address_text = null;
      nextCtx.delivery.reference_text = null;

      nextCtx.step = 'awaiting_order_confirmation';
      replyText =
        replyText ||
        'Perfecto, lo registraré para recojo en tienda. Voy a mostrarte el resumen de tu pedido.';
      newStep = 'awaiting_order_confirmation';
      applyAction = 'build_pickup_summary';
      break;
    }

    nextCtx.step = 'awaiting_address';
    replyText =
      replyText ||
      'Perfecto, lo registramos como delivery. Ahora compárteme la dirección de entrega.';
    newStep = 'awaiting_address';
    applyAction = 'reply_now';
    break;
  }

  case 'provide_address': {
    const address = extracted.address_text ? String(extracted.address_text).trim() : null;

    nextCtx.flow = 'delivery';
    nextCtx.intent = 'delivery_order';

    if (!address || address.length < 6) {
      nextCtx.step = 'awaiting_address';
      replyText =
        replyText ||
        'Compárteme una dirección más completa para el delivery.';
      newStep = 'awaiting_address';
      applyAction = 'reply_now';
      break;
    }

    nextCtx.delivery.address_text = address;
    nextCtx.step = 'awaiting_reference';
    replyText =
      replyText ||
      'Perfecto. Ahora indícame una referencia para ubicar mejor la dirección.';
    newStep = 'awaiting_reference';
    applyAction = 'calculate_delivery';
    break;
  }

  case 'provide_reference': {
    const reference = extracted.reference_text ? String(extracted.reference_text).trim() : null;

    nextCtx.flow = 'delivery';
    nextCtx.intent = 'delivery_order';
    nextCtx.delivery.reference_text = reference || null;
    nextCtx.step = 'awaiting_district';

    replyText =
      replyText ||
      'Perfecto. Ahora indícame tu distrito o zona para calcular el delivery.';
    newStep = 'awaiting_district';
    applyAction = 'calculate_delivery';
    break;
  }

  case 'provide_district': {
    const district = extracted.district ? String(extracted.district).trim() : null;

    nextCtx.flow = 'delivery';
    nextCtx.intent = 'delivery_order';

    if (!district || district.length < 2) {
      nextCtx.step = 'awaiting_district';
      replyText =
        replyText ||
        'Indícame tu distrito o zona para calcular el delivery.';
      newStep = 'awaiting_district';
      applyAction = 'reply_now';
      break;
    }

    nextCtx.delivery.district = district;
    nextCtx.step = 'awaiting_order_confirmation';
    replyText =
      replyText ||
      'Gracias. Voy a calcular el costo de delivery y mostrarte el resumen de tu pedido.';
    newStep = 'awaiting_order_confirmation';
    applyAction = 'calculate_delivery';
    break;
  }

  case 'confirm_order': {
    const confirmation = extracted.confirmation;

    nextCtx.flow = 'delivery';
    nextCtx.intent = 'delivery_order';

    if (confirmation !== 'yes') {
      nextCtx.step = 'awaiting_order_confirmation';
      replyText =
        replyText ||
        'Respóndeme si deseas confirmar el pedido con un "sí" o "no".';
      newStep = 'awaiting_order_confirmation';
      applyAction = 'reply_now';
      break;
    }

    nextCtx.step = 'completed';

    replyText =
      replyText ||
      '¡Perfecto! Tu pedido ha sido recibido. Envíanos tu constancia de pago para confirmarlo y comenzar a prepararlo.';

    newStep = 'completed';
    applyAction = 'persist_order';

    orderSummary = {
      subtotal: cartSubtotal(nextCtx.cart),
      delivery_fee: Number(nextCtx.delivery.delivery_fee || 0),
      total: Number(
        (cartSubtotal(nextCtx.cart) + Number(nextCtx.delivery.delivery_fee || 0)).toFixed(2)
      )
    };

    break;
  }

  case 'reject_order': {
    nextCtx.flow = 'delivery';
    nextCtx.step = 'awaiting_post_cart_decision';
    nextCtx.intent = 'delivery_order';

    replyText =
      replyText ||
      'Entendido. Indícame si deseas agregar algo más o qué deseas cambiar.';
    newStep = 'awaiting_post_cart_decision';
    applyAction = 'reply_now';
    break;
  }

  case 'cancel_order':
  case 'restart_order': {
    nextCtx.flow = 'delivery';
    nextCtx.step = 'cancelled';
    nextCtx.intent = 'delivery_order';
    nextCtx.cart = [];
    nextCtx.delivery = {
      fulfillment_type: null,
      eta_max: null,
      eta_min: null,
      zone_id: null,
      district: null,
      address_text: null,
      delivery_fee: null,
      reference_text: null
    };

    replyText =
      replyText ||
      'Listo, cancelé el pedido actual. Si deseas, puedo ayudarte a empezar uno nuevo.';
    newStep = 'cancelled';
    applyAction = 'reply_now';
    break;
  }

  default: {
    if (currentStep === 'awaiting_post_cart_decision' && Array.isArray(nextCtx.cart) && nextCtx.cart.length > 0) {
      const normalized = String(original.message_text || '').trim().toLowerCase();
      const continueWords = [
        'continuamos', 'continuar', 'continua', 'continúe', 'continua nomas',
        'seguimos', 'sigue', 'prosigue', 'proseguir',
        'eso es todo', 'nada mas', 'nada más', 'ya', 'listo', 'ok', 'dale'
      ];

      if (continueWords.some(w => normalized.includes(w))) {
        const next = goToCheckout();
        nextCtx.flow = 'delivery';
        nextCtx.intent = 'delivery_order';
        replyText = next.reply;
        newStep = next.step;
        applyAction = 'reply_now';
        break;
      }
    }

    nextCtx.flow = 'delivery';
    nextCtx.step = currentStep;
    nextCtx.intent = 'delivery_order';

    replyText =
      replyText ||
      'No logré determinar exactamente qué necesitas. Indícame qué deseas pedir o el dato que falta.';
    newStep = currentStep;
    applyAction = 'reply_now';
    break;
  }
}

return [
  {
    json: {
      ...original,
      interpreter_result: parsed,
      reply_text: replyText,
      new_flow: 'delivery',
      new_step: newStep,
      context_json: nextCtx,
      apply_action: applyAction,
      order_summary: orderSummary
    }
  }
];

const input = $('When Executed by Another Workflow').first().json || {};

const intent = String(input.intent || '').trim().toLowerCase();
const confidence = Number(input.confidence || 0);
const messageText = String(input.message_text || '').trim().toLowerCase();

const currentFlow = String(input.current_flow || input.context_json?.flow || '').trim().toLowerCase();
const currentStep = String(input.current_step || input.context_json?.step || '').trim().toLowerCase();

const ctx = input.context_json ?? {};

const greetingIntents = ['greeting', 'welcome', 'hello', 'hi'];
const deliveryIntents = [
  'delivery',
  'order_food',
  'delivery_order',
  'menu',
  'menu_request',
  'product_inquiry'
];
const eventIntents = ['events', 'event_inquiry', 'event_booking', 'event_quote'];

const greetingWords = ['hola', 'buenas', 'buenos días', 'buenas tardes', 'buenas noches', 'hi', 'hello'];
const resetWords = ['cancelar', 'reiniciar', 'empezar de nuevo', 'volver al inicio', 'menu principal', 'menú principal'];

function includesAny(text, words) {
  return words.some(w => text.includes(w));
}

let route_target = 'welcome_reply';
let route_reason = 'default';
let normalized_intent = intent || 'unknown';

if (includesAny(messageText, resetWords)) {
  route_target = 'reset_to_welcome';
  route_reason = 'explicit_reset';
} else if (
  greetingIntents.includes(intent) ||
  currentFlow === 'welcome' ||
  currentStep === 'awaiting_user_choice' ||
  includesAny(messageText, greetingWords)
) {
  if (includesAny(messageText, ['1', 'carta', 'ver carta', 'menu', 'menú'])) {
    route_target = 'delivery_flow';
    route_reason = 'welcome_choice_menu';
    normalized_intent = 'menu';
  } else if (includesAny(messageText, ['2', 'pedido', 'hacer pedido', 'ordenar'])) {
    route_target = 'delivery_flow';
    route_reason = 'welcome_choice_delivery';
    normalized_intent = 'delivery_order';
  } else if (includesAny(messageText, ['3', 'eventos', 'cotizar evento', 'evento'])) {
    route_target = 'events_flow';
    route_reason = 'welcome_choice_events';
    normalized_intent = 'event_inquiry';
  } else {
    route_target = 'welcome_reply';
    route_reason = 'greeting_or_welcome';
  }
} else if (currentFlow === 'delivery') {
  if (eventIntents.includes(intent) || includesAny(messageText, ['evento', 'eventos', 'cotización', 'cotizar'])) {
    route_target = 'events_flow';
    route_reason = 'change_topic_to_events';
  } else {
    route_target = 'delivery_flow';
    route_reason = 'continue_delivery';
  }
} else if (currentFlow === 'events') {
  if (deliveryIntents.includes(intent) || includesAny(messageText, ['pedido', 'carta', 'chaufa', 'delivery'])) {
    route_target = 'delivery_flow';
    route_reason = 'change_topic_to_delivery';
  } else {
    route_target = 'events_flow';
    route_reason = 'continue_events';
  }
} else if (deliveryIntents.includes(intent)) {
  route_target = 'delivery_flow';
  route_reason = 'intent_delivery';
} else if (eventIntents.includes(intent)) {
  route_target = 'events_flow';
  route_reason = 'intent_events';
} else {
  route_target = 'welcome_reply';
  route_reason = 'fallback_welcome';
}

return [
  {
    json: {
      ...input,
      normalized_intent,
      route_target,
      route_reason,
      routing_debug: {
        intent,
        confidence,
        current_flow: currentFlow,
        current_step: currentStep,
        message_text: messageText
      }
    }
  }
];

