const original = $('When Executed by Another Workflow').first().json || {};
const ctx = original.context_json ?? {};

const normalizedCart = Array.isArray(ctx.cart)
  ? ctx.cart.map(item => ({
      product_code: item.product_code ?? item.item_code ?? null,
      product_name: item.product_name ?? item.item_name ?? null,
      quantity: Number(item.quantity ?? 1),
      unit_price: Number(item.unit_price ?? 0),
      line_subtotal: Number(item.line_subtotal ?? 0),
      configuration: item.configuration ?? null,
      extras: Array.isArray(item.extras) ? item.extras : []
    }))
  : [];

const orderDraft = ctx.order_draft ?? {
  items: normalizedCart,
  customer: ctx.customer ?? {},
  fulfillment_type: ctx.delivery?.fulfillment_type ?? null,
  address_text: ctx.delivery?.address_text ?? null,
  reference_text: ctx.delivery?.reference_text ?? null,
  district: ctx.delivery?.district ?? null,
  zone_id: ctx.delivery?.zone_id ?? null,
  delivery_fee: ctx.delivery?.delivery_fee ?? null,
  eta_min: ctx.delivery?.eta_min ?? null,
  eta_max: ctx.delivery?.eta_max ?? null,
  summary_ready: false,
  confirmed: false
};
if (orderDraft.fulfillment_type === null && ctx.delivery?.fulfillment_type) {
  orderDraft.fulfillment_type = ctx.delivery.fulfillment_type;
}
return [
  {
    json: {
      conversation_id: original.conversation_id ?? null,
      customer_id: original.customer_id ?? null,
      telegram_chat_id: original.telegram_chat_id ?? null,
      channel: original.channel ?? 'telegram',
      message_text: String(original.message_text ?? '').trim(),
      current_flow: original.current_flow ?? ctx.flow ?? 'delivery',
      current_step: original.current_step ?? ctx.step ?? null,
      customer_name: original.customer_name ?? ctx.customer?.name ?? null,
      context_json: ctx,
      order_draft: orderDraft,
      guidance: {
        phase: 'delivery_v3_phase_1',
        allowed_actions: [
          'reply',
          'show_menu',
          'show_product_detail',
          'update_draft',
          'ask_missing'
        ]
      }
    }
  }
];

const raw =
  $json.output ??
  $json.text ??
  $json.response ??
  $json.message ??
  '';

let parsed;

try {
  parsed = typeof raw === 'string' ? JSON.parse(raw) : raw;
} catch (e) {
  parsed = {
    action: 'reply',
    message: 'No logré interpretar bien tu mensaje. ¿Podrías decírmelo de otra forma?',
    business_intent: 'unknown',
    draft_patch: {},
    needs_persistence: false,
    confidence: 0,
    tool_evidence: {
      used_tools: []
    }
  };
}

parsed = {
  action: parsed?.action ?? 'reply',
  message: parsed?.message ?? 'No logré interpretar bien tu mensaje. ¿Podrías decírmelo de otra forma?',
  business_intent: parsed?.business_intent ?? 'unknown',
  draft_patch:
    parsed?.draft_patch && typeof parsed.draft_patch === 'object'
      ? parsed.draft_patch
      : {},
  needs_persistence: Boolean(parsed?.needs_persistence),
  confidence:
    parsed?.confidence === null || parsed?.confidence === undefined || parsed?.confidence === ''
      ? 0
      : Number(parsed.confidence),
  tool_evidence: {
    used_tools: Array.isArray(parsed?.tool_evidence?.used_tools)
      ? parsed.tool_evidence.used_tools
      : []
  }
};

return [{ json: parsed }];

