const original = $('Build Delivery Agent Input').first().json;
const parsed = $('Parse agent output').first().json;

const ctx = original.context_json ?? {};
const preservedFlow = ctx.flow ?? original.current_flow ?? 'delivery';
const preservedStep = ctx.step ?? original.current_step ?? 'delivery_active';

return [
  {
    json: {
      ...original,
      agent_result: parsed,
      reply_text: parsed.message,
      business_intent: parsed.business_intent,
      draft_patch: parsed.draft_patch ?? {},
      needs_persistence: parsed.needs_persistence ?? false,
      action: parsed.action,

      // No forzar aquí delivery_active; se preserva el paso actual
      // y luego los nodos determinísticos lo cambian si corresponde.
      new_flow: preservedFlow,
      new_step: preservedStep,

      context_json: {
        ...ctx,
        flow: preservedFlow,
        step: preservedStep,
        last_agent_action: parsed.action,
        last_menu_shown_at:
          parsed.action === 'show_menu'
            ? new Date().toISOString()
            : (ctx.last_menu_shown_at ?? null)
      }
    }
  }
];

const input = $input.first().json;
const ctx = input.context_json ?? {};

const baseCustomer = ctx.customer ?? {};
const legacyDelivery = ctx.delivery ?? {};
const existingDraft = ctx.order_draft ?? {};

const rawMessage = String(input.message_text ?? '').trim().toLowerCase();

const looksLikeDeliveryChoice = [
  'delivery',
  'delívery',
  'envio',
  'envío',
  'para delivery',
  'quiero delivery'
].includes(rawMessage);

const looksLikePickupChoice = [
  'pickup',
  'recojo',
  'recoger',
  'recojo en tienda',
  'para recojo'
].includes(rawMessage);

// heurística simple para dirección
const looksLikeAddress =
  /\d/.test(rawMessage) &&
  (
    rawMessage.includes('jr') ||
    rawMessage.includes('jiron') ||
    rawMessage.includes('jirón') ||
    rawMessage.includes('calle') ||
    rawMessage.includes('av') ||
    rawMessage.includes('avenida') ||
    rawMessage.includes('mz') ||
    rawMessage.includes('lt')
  );

const orderDraft = {
  items: Array.isArray(existingDraft.items)
    ? existingDraft.items
    : (Array.isArray(ctx.cart) ? ctx.cart : []),

  customer: existingDraft.customer ?? {
    name: baseCustomer.name ?? null,
    phone: baseCustomer.phone ?? null
  },

  fulfillment_type:
    existingDraft.fulfillment_type ??
    legacyDelivery.fulfillment_type ??
    null,

  address_text:
    existingDraft.address_text ??
    legacyDelivery.address_text ??
    null,

  reference_text:
    existingDraft.reference_text ??
    legacyDelivery.reference_text ??
    null,

  district:
    existingDraft.district ??
    legacyDelivery.district ??
    null,

  zone_id:
    existingDraft.zone_id ??
    legacyDelivery.zone_id ??
    null,

  delivery_fee:
    existingDraft.delivery_fee ??
    legacyDelivery.delivery_fee ??
    null,

  eta_min:
    existingDraft.eta_min ??
    legacyDelivery.eta_min ??
    null,

  eta_max:
    existingDraft.eta_max ??
    legacyDelivery.eta_max ??
    null,

  summary_ready: existingDraft.summary_ready ?? false,
  confirmed: existingDraft.confirmed ?? false
};

orderDraft.items = Array.isArray(orderDraft.items) ? orderDraft.items : [];
orderDraft.customer = orderDraft.customer ?? {
  name: baseCustomer.name ?? null,
  phone: baseCustomer.phone ?? null
};

const patch = input.draft_patch ?? {};
const addItems = Array.isArray(patch.add_items) ? patch.add_items : [];
const removeItems = Array.isArray(patch.remove_items) ? patch.remove_items : [];
const replaceItems = Array.isArray(patch.replace_items) ? patch.replace_items : [];

// Reset completo del draft/contexto
if (patch.reset_draft === true) {
  const preservedCustomer = {
    name: orderDraft.customer?.name ?? baseCustomer.name ?? null,
    phone: orderDraft.customer?.phone ?? baseCustomer.phone ?? null
  };

  const resetDraft = {
    items: [],
    customer: preservedCustomer,
    fulfillment_type: null,
    address_text: null,
    reference_text: null,
    district: null,
    zone_id: null,
    delivery_fee: null,
    eta_min: null,
    eta_max: null,
    summary_ready: false,
    confirmed: false
  };

  const newCtx = {
    flow: 'delivery',
    step: 'delivery_active',
    intent: 'greeting',
    customer: preservedCustomer,
    cart: [],
    delivery: {
      fulfillment_type: null,
      eta_max: null,
      eta_min: null,
      zone_id: null,
      district: null,
      address_text: null,
      delivery_fee: null,
      reference_text: null
    },
    order_draft: resetDraft,
    last_agent_action: input.action
  };

  return [
    {
      json: {
        ...input,
        context_json: newCtx,
        new_flow: 'delivery',
        new_step: 'delivery_active'
      }
    }
  ];
}

// Agregar items
for (const item of addItems) {
  const qty = Number(item.quantity || 1);
  const unitPrice = Number(item.unit_price || 0);

  const existing = orderDraft.items.find(i => i.product_code === item.product_code);

  if (existing) {
    existing.quantity = Number(existing.quantity || 0) + qty;
    existing.unit_price = unitPrice || Number(existing.unit_price || 0);
    existing.line_subtotal = Number((existing.quantity * existing.unit_price).toFixed(2));
  } else {
    orderDraft.items.push({
      product_code: item.product_code ?? null,
      product_name: item.product_name ?? null,
      quantity: qty,
      unit_price: unitPrice,
      line_subtotal: Number((qty * unitPrice).toFixed(2)),
      configuration: item.configuration ?? null,
      extras: Array.isArray(item.extras) ? item.extras : []
    });
  }
}

// Quitar items
for (const item of removeItems) {
  const qty = Number(item.quantity || 1);
  const existing = orderDraft.items.find(i => i.product_code === item.product_code);

  if (!existing) continue;

  existing.quantity = Number(existing.quantity || 0) - qty;

  if (existing.quantity <= 0) {
    orderDraft.items = orderDraft.items.filter(i => i.product_code !== item.product_code);
  } else {
    existing.line_subtotal = Number((existing.quantity * Number(existing.unit_price || 0)).toFixed(2));
  }
}

// Reemplazar items
for (const item of replaceItems) {
  const fromCode = item.from_product_code ?? null;
  const toCode = item.to_product_code ?? null;
  const qty = Number(item.quantity || 1);
  const unitPrice = Number(item.unit_price || 0);

  if (fromCode) {
    orderDraft.items = orderDraft.items.filter(i => i.product_code !== fromCode);
  }

  if (toCode) {
    orderDraft.items.push({
      product_code: toCode,
      product_name: item.to_product_name ?? null,
      quantity: qty,
      unit_price: unitPrice,
      line_subtotal: Number((qty * unitPrice).toFixed(2)),
      configuration: item.configuration ?? null,
      extras: Array.isArray(item.extras) ? item.extras : []
    });
  }
}

// Datos cliente
if (patch.customer && typeof patch.customer === 'object') {
  if (patch.customer.name) {
    orderDraft.customer.name = String(patch.customer.name).trim();
  }
  if (patch.customer.phone) {
    orderDraft.customer.phone = String(patch.customer.phone).replace(/\D/g, '');
  }
}

// Fulfillment desde patch
if (patch.fulfillment_type) {
  orderDraft.fulfillment_type = String(patch.fulfillment_type).trim().toLowerCase();
}

// Fulfillment por fallback determinístico
if (!orderDraft.fulfillment_type) {
  if (looksLikeDeliveryChoice) {
    orderDraft.fulfillment_type = 'delivery';
  } else if (looksLikePickupChoice) {
    orderDraft.fulfillment_type = 'pickup';
  }
}

// Dirección
if (patch.address_text) {
  orderDraft.address_text = String(patch.address_text).trim();
}

// Referencia
if (patch.reference_text) {
  orderDraft.reference_text = String(patch.reference_text).trim();
}

// Distrito
if (patch.district) {
  orderDraft.district = String(patch.district).trim();
}

// Si el usuario escribió algo que parece dirección y ya estaba en checkout,
// mantener o asumir delivery para la demo
if (looksLikeAddress) {
  if (!orderDraft.address_text) {
    orderDraft.address_text = String(input.message_text ?? '').trim();
  }

  if (!orderDraft.fulfillment_type) {
    orderDraft.fulfillment_type = 'delivery';
  }
}

// Heurística para separar distrito si vino junto con dirección
if (!orderDraft.district && looksLikeAddress) {
  const knownDistricts = [
    'magdalena',
    'iquitos',
    'los olivos',
    'san martin de porres',
    'san martín de porres',
    'independencia',
    'comas'
  ];

  const foundDistrict = knownDistricts.find(d => rawMessage.includes(d));
  if (foundDistrict) {
    orderDraft.district = foundDistrict
      .split(' ')
      .map(w => w.charAt(0).toUpperCase() + w.slice(1))
      .join(' ');
  }
}

// Solicitud de resumen
if (patch.request_summary === true) {
  orderDraft.summary_ready = true;
}

// Preservar fulfillment_type aunque el patch actual no lo traiga
orderDraft.fulfillment_type =
  orderDraft.fulfillment_type ??
  existingDraft.fulfillment_type ??
  legacyDelivery.fulfillment_type ??
  null;

// Sincronizar customer
const syncedCustomer = {
  name: orderDraft.customer?.name ?? baseCustomer.name ?? null,
  phone: orderDraft.customer?.phone ?? baseCustomer.phone ?? null
};

// Sincronizar delivery de forma defensiva
const syncedDelivery = {
  fulfillment_type:
    orderDraft.fulfillment_type ??
    existingDraft.fulfillment_type ??
    legacyDelivery.fulfillment_type ??
    null,

  eta_max:
    orderDraft.eta_max ??
    existingDraft.eta_max ??
    legacyDelivery.eta_max ??
    null,

  eta_min:
    orderDraft.eta_min ??
    existingDraft.eta_min ??
    legacyDelivery.eta_min ??
    null,

  zone_id:
    orderDraft.zone_id ??
    existingDraft.zone_id ??
    legacyDelivery.zone_id ??
    null,

  district:
    orderDraft.district ??
    existingDraft.district ??
