const input = $input.first().json;
const ctx = input.context_json ?? {};
const draft = ctx.order_draft ?? {};

const items = Array.isArray(draft.items) ? draft.items : [];
const customer = draft.customer ?? {};

let replyText = input.reply_text || 'Perfecto.';
let action = input.action || 'reply';
let nextStep = 'delivery_active';

const currentStep = ctx.step ?? input.current_step ?? null;
const isAwaitingFinalConfirmation = currentStep === 'awaiting_final_confirmation';

const rawMessage = String(input.message_text ?? '').trim().toLowerCase();
const normalizedMessage = rawMessage
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '');

const yesWords = ['si', 'sí', 'ok', 'dale', 'confirmar', 'confirmado', 'acepto', 'yes'];
const noWords = ['no', 'todavia no', 'todavía no', 'cambiar', 'modificar', 'ajustar'];

const isYesReply =
  yesWords.includes(normalizedMessage) ||
  /^(si|sí|ok|dale|confirmar|confirmado|acepto|yes)$/i.test(rawMessage);

const isNoReply =
  noWords.includes(normalizedMessage) ||
  /^(no|todavia no|todavía no|cambiar|modificar|ajustar)$/i.test(rawMessage);

// Fallback determinístico cuando ya estamos esperando confirmación final
let effectiveBusinessIntent = input.business_intent ?? 'unknown';
if (isAwaitingFinalConfirmation) {
  if (isYesReply) {
    effectiveBusinessIntent = 'final_confirmation_yes';
  } else if (isNoReply) {
    effectiveBusinessIntent = 'final_confirmation_no';
  }
}

const hasItems = items.length > 0;
const hasName = !!(customer.name && String(customer.name).trim());
const hasPhone = !!(customer.phone && String(customer.phone).replace(/\D/g, '').length >= 9);

const fulfillment = draft.fulfillment_type ?? null;
const isDelivery = fulfillment === 'delivery';
const isPickup = fulfillment === 'pickup';

const hasDistrict = !!(draft.district && String(draft.district).trim());
const hasAddress = !!(draft.address_text && String(draft.address_text).trim());

const rawReference = draft.reference_text == null ? '' : String(draft.reference_text).trim();

const hasZone = !!draft.zone_id || Number(draft.delivery_fee || 0) > 0;
const hasDeliveryFee = draft.delivery_fee !== null && draft.delivery_fee !== undefined;

const subtotal = Number(
  items.reduce((sum, item) => sum + Number(item.line_subtotal || 0), 0).toFixed(2)
);

function buildSummary() {
  const lines = items.map(
    item => `- ${item.quantity} x ${item.product_name} — S/ ${Number(item.line_subtotal || 0).toFixed(2)}`
  );

  const deliveryFee = Number(isPickup ? 0 : (draft.delivery_fee || 0));
  const total = Number((subtotal + deliveryFee).toFixed(2));
  const modeText = isPickup ? 'Recojo en tienda' : isDelivery ? 'Delivery' : 'Por definir';

  let summary = `Perfecto, este es el resumen actual de tu pedido:\n\n${lines.join('\n')}\n\nSubtotal: S/ ${subtotal.toFixed(2)}\nDelivery: S/ ${deliveryFee.toFixed(2)}\nTotal: S/ ${total.toFixed(2)}\n\nModalidad: ${modeText}\nNombre: ${customer.name || '-'}\nTeléfono: ${customer.phone || '-'}`;

  if (isDelivery) {
    summary += `\nDistrito: ${draft.district || '-'}\nDirección: ${draft.address_text || '-'}\nReferencia: ${rawReference || '-'}`;

    if (draft.eta_min && draft.eta_max) {
      summary += `\nTiempo estimado: ${draft.eta_min} a ${draft.eta_max} min`;
    }
  }

  return summary;
}

function getMissingFields() {
  const missing = [];
  if (!hasItems) missing.push('items');
  if (!hasName) missing.push('name');
  if (!hasPhone) missing.push('phone');
  if (!fulfillment) missing.push('fulfillment_type');
  if (isDelivery && !hasDistrict) missing.push('district');
  if (isDelivery && !hasAddress) missing.push('address_text');
  return missing;
}

const missing = getMissingFields();

const itemEditIntents = [
  'add_items',
  'remove_items',
  'increase_quantity',
  'decrease_quantity',
  'replace_item'
];

// Si acaba de modificar items y no ha pedido continuar explícitamente,
// no saltar a checkout; invitar a seguir pidiendo.
if (
  hasItems &&
  itemEditIntents.includes(effectiveBusinessIntent) &&
  !isAwaitingFinalConfirmation
) {
  replyText = input.reply_text || 'Perfecto. ¿Deseas agregar algo más o continuamos?';
  action = 'reply';
  nextStep = 'delivery_active';

  return [
    {
      json: {
        ...input,
        business_intent: effectiveBusinessIntent,
        action,
        reply_text: replyText,
        new_flow: 'delivery',
        new_step: nextStep,
        context_json: {
          ...ctx,
          flow: 'delivery',
          step: nextStep,
          order_draft: {
            ...draft,
            summary_ready: false,
            confirmed: false
          }
        }
      }
    }
  ];
}

// Si ya estamos esperando confirmación final y el usuario escribe algo que no sea
// sí / no / confirmar ni un update_draft real, salimos del modo confirmación
// para permitir que ajuste el pedido en vez de repetir el resumen.
if (
  isAwaitingFinalConfirmation &&
  effectiveBusinessIntent !== 'final_confirmation_yes' &&
  effectiveBusinessIntent !== 'final_confirmation_no' &&
  effectiveBusinessIntent !== 'confirm_order' &&
  input.action !== 'update_draft'
) {
  replyText = 'Claro. Indícame qué deseas agregar o qué cambio quieres hacer en tu pedido.';
  action = 'reply';
  nextStep = 'delivery_active';

  return [
    {
      json: {
        ...input,
        business_intent: effectiveBusinessIntent,
        action,
        reply_text: replyText,
        new_flow: 'delivery',
        new_step: nextStep,
        context_json: {
          ...ctx,
          flow: 'delivery',
          step: nextStep,
          order_draft: {
            ...draft,
            summary_ready: false,
            confirmed: false
          }
        }
      }
    }
  ];
}

if (
  hasItems &&
  normalizedMessage === 'no' &&
  !isAwaitingFinalConfirmation
) {
  effectiveBusinessIntent = 'continue_checkout';
}

const shouldReevaluateCheckout =
  hasItems &&
  (
    effectiveBusinessIntent === 'continue_checkout' ||
    (
      input.action === 'update_draft' &&
      !itemEditIntents.includes(effectiveBusinessIntent)
    ) ||
    (
      currentStep !== 'awaiting_final_confirmation' &&
      draft.summary_ready === true
    )
  );

// 1) Recalcular el siguiente paso siempre que haya cambios orientados a checkout
if (shouldReevaluateCheckout) {
  if (!hasName) {
    replyText = 'Perfecto. Indícame tu nombre para registrar el pedido.';
    action = 'ask_missing';
    nextStep = 'delivery_active';
  } else if (!hasPhone) {
    replyText = `Gracias, ${customer.name}. Ahora compárteme tu número de celular.`;
    action = 'ask_missing';
    nextStep = 'delivery_active';
  } else if (!fulfillment) {
    replyText = 'Gracias. ¿Tu pedido es para delivery o para recojo en tienda?';
    action = 'ask_missing';
    nextStep = 'delivery_active';
  } else if (isPickup) {
    replyText = `${buildSummary()}\n\n¿Deseas confirmar tu pedido? Puedes responder: sí o no.`;
    action = 'confirm_order';
    nextStep = 'awaiting_final_confirmation';
  } else if (isDelivery && !hasDistrict) {
    replyText = 'Perfecto. Indícame tu distrito para validar la zona de delivery.';
    action = 'ask_missing';
    nextStep = 'delivery_active';
  } else if (isDelivery && (!hasZone || !hasDeliveryFee || !draft.zone_id)) {
    replyText = 'Perfecto, voy a validar tu zona de delivery.';
    action = 'update_draft';
    nextStep = 'delivery_quote_pending';
  } else if (isDelivery && !hasAddress) {
    replyText = 'Perfecto. Ahora compárteme la dirección de entrega.';
    action = 'ask_missing';
    nextStep = 'delivery_active';
  } else {
    replyText = `${buildSummary()}\n\n¿Deseas confirmar tu pedido? Puedes responder: sí o no.`;
    action = 'confirm_order';
    nextStep = 'awaiting_final_confirmation';
  }
}

// 2) Si el usuario intenta confirmar antes de tiempo
if (effectiveBusinessIntent === 'confirm_order') {
  if (missing.length > 0) {
    if (missing.includes('name')) {
      replyText = 'Para confirmar tu pedido necesito tu nombre.';
    } else if (missing.includes('phone')) {
      replyText = 'Para confirmar tu pedido necesito tu número de celular.';
    } else if (missing.includes('fulfillment_type')) {
      replyText = 'Para confirmar tu pedido necesito que me indiques si lo quieres para delivery o para recojo en tienda.';
    } else if (missing.includes('district')) {
      replyText = 'Para confirmar el delivery necesito tu distrito.';
    } else if (missing.includes('address_text')) {
      replyText = 'Para confirmar el delivery necesito tu dirección.';
    } else if (missing.includes('items')) {
      replyText = 'Aún no tengo productos en tu pedido. Indícame qué deseas pedir.';
    }

    action = 'ask_missing';
    nextStep = 'delivery_active';
  } else if (isDelivery && (!hasZone || !hasDeliveryFee)) {
    replyText = 'Antes de confirmar, necesito validar el costo y tiempo estimado del delivery.';
    action = 'update_draft';
    nextStep = 'delivery_quote_pending';
  } else {
    replyText = `${buildSummary()}\n\nResponde "sí" para confirmarlo o indícame cualquier ajuste.`;
    action = 'confirm_order';
    nextStep = 'awaiting_final_confirmation';
  }
}

// 3) Confirmación final positiva
if (effectiveBusinessIntent === 'final_confirmation_yes') {
  if (missing.length > 0) {
    replyText = 'Aún faltan datos para confirmar el pedido. Indícame lo que falta y continuamos.';
    action = 'ask_missing';
    nextStep = 'delivery_active';
  } else if (isDelivery && (!hasZone || !hasDeliveryFee)) {
    replyText = 'Antes de confirmar, necesito validar el costo del delivery.';
    action = 'update_draft';
    nextStep = 'delivery_quote_pending';
  } else {
    replyText = '¡Perfecto! Tu pedido ha sido confirmado y ahora pasará a preparación. En breve te compartimos los medios de pago o la siguiente indicación.';
    action = 'confirm_order';
    nextStep = 'confirmed';
  }
}

// 4) Confirmación final negativa
if (effectiveBusinessIntent === 'final_confirmation_no') {
  replyText = 'Entendido. Indícame qué deseas ajustar en tu pedido.';
  action = 'reply';
  nextStep = 'delivery_active';
}

return [
  {
    json: {
      ...input,
      business_intent: effectiveBusinessIntent,
      action,
      reply_text: replyText,
      new_flow: 'delivery',
      new_step: nextStep,
      context_json: {
        ...ctx,
        flow: 'delivery',
        step: nextStep,
        order_draft: {
          ...draft,
          summary_ready: action === 'show_summary' || action === 'confirm_order',
          confirmed: nextStep === 'confirmed'
        }
      }
    }
  }
];

