      ...input,
      action: 'reply',
      reply_text: 'Recibí tu imagen. La validación automática de constancias será habilitada en el siguiente paso.',
      new_flow: 'delivery',
      new_step: 'awaiting_payment',
      context_json: {
        ...(input.context_json ?? {}),
        flow: 'delivery',
        step: 'awaiting_payment'
      }
    }
  }
];

const input = $input.first().json || {};

// 1) Si ya vienen campos normalizados, respetarlos
const normalizedHasImage =
  input.has_image === true ||
  input.has_image === 'true' ||
  input.has_image === 1 ||
  input.has_image === '1';

const normalizedMediaKind = input.media_kind ?? null;
const normalizedPhotoId = input.telegram_photo_file_id ?? null;
const normalizedImageDocId = input.telegram_image_file_id ?? null;
const normalizedPdfDocId = input.telegram_document_file_id ?? null;
const normalizedFileId = input.telegram_file_id ?? null;

if (
  normalizedHasImage &&
  (normalizedPhotoId || normalizedImageDocId || normalizedPdfDocId || normalizedFileId)
) {
  return [
    {
      json: {
        ...input,
        has_image: true,
        media_kind: normalizedMediaKind ?? 'unknown',
        telegram_photo_file_id: normalizedPhotoId,
        telegram_image_file_id: normalizedImageDocId,
        telegram_document_file_id: normalizedPdfDocId,
        telegram_file_id:
          normalizedFileId ??
          normalizedPhotoId ??
          normalizedImageDocId ??
          normalizedPdfDocId,
      }
    }
  ];
}

// 2) Si no viene normalizado, intentar reconstruir desde raw_payload
let raw = input.raw_payload ?? input.telegram_raw ?? input.raw ?? {};

if (typeof raw === 'string') {
  try {
    raw = JSON.parse(raw);
  } catch (e) {
    raw = {};
  }
}

const photoArray =
  raw?.message?.photo ||
  raw?.photo ||
  [];

const documentObj =
  raw?.message?.document ||
  raw?.document ||
  null;

let telegram_photo_file_id = null;
let telegram_image_file_id = null;
let telegram_document_file_id = null;
let media_kind = 'none';
let has_image = false;
let mime_type = input.mime_type ?? null;
let file_name = input.file_name ?? null;

if (Array.isArray(photoArray) && photoArray.length > 0) {
  const largestPhoto = photoArray[photoArray.length - 1];
  telegram_photo_file_id = largestPhoto?.file_id ?? null;
  media_kind = 'photo';
  has_image = Boolean(telegram_photo_file_id);
}

if (!has_image && documentObj?.file_id) {
  mime_type = documentObj.mime_type ?? mime_type;
  file_name = documentObj.file_name ?? file_name;

  if ((mime_type || '').startsWith('image/')) {
    telegram_image_file_id = documentObj.file_id;
    media_kind = 'image_document';
    has_image = true;
  } else if (mime_type === 'application/pdf') {
    telegram_document_file_id = documentObj.file_id;
    media_kind = 'pdf_document';
    has_image = true;
  }
}

return [
  {
    json: {
      ...input,
      has_image,
      media_kind,
      mime_type,
      file_name,
      telegram_photo_file_id,
      telegram_image_file_id,
      telegram_document_file_id,
      telegram_file_id:
        telegram_photo_file_id ??
        telegram_image_file_id ??
        telegram_document_file_id ??
        null
    }
  }
];

const input = $input.first().json || {};
const blockingOrder = input.blocking_order || {};

if (!input.telegram_file_id) {
  throw new Error('No existe telegram_file_id para analizar');
}

if (!blockingOrder.id) {
  throw new Error('No existe blocking_order.id para análisis de voucher');
}

return [
  {
    json: {
      channel: input.channel ?? 'telegram',
      conversation_id: input.conversation_id ?? null,
      customer_id: input.customer_id ?? null,
      telegram_chat_id: input.telegram_chat_id ?? null,
      telegram_photo_file_id: input.telegram_photo_file_id ?? null,
      telegram_image_file_id: input.telegram_image_file_id ?? null,
      telegram_document_file_id: input.telegram_document_file_id ?? null,
      telegram_file_id: input.telegram_file_id ?? null,
      mime_type: input.mime_type ?? null,
      file_name: input.file_name ?? null,
      blocking_order: {
        id: blockingOrder.id,
        order_status: blockingOrder.order_status ?? null,
        total_amount: blockingOrder.total_amount ?? null
      },
      analysis_profile: 'payment_receipt'
    }
  }
];

const originalCtx = $json.context_json || {};

return [
  {
    json: {
      ...$json,
      new_context_json: {
        ...originalCtx,
        flow: 'delivery',
        step:
          $json.decision === 'manual_review_required'
            ? 'awaiting_payment_validation'
            : originalCtx.step ?? 'awaiting_payment',
        last_pending_payment_order: {
          ...(originalCtx.last_pending_payment_order || {}),
          order_id: $json.order_id,
          order_status:
            $json.decision === 'manual_review_required'
              ? 'paid_pending_confirmation'
              : (originalCtx.last_pending_payment_order?.order_status || 'pending_payment'),
          total_amount: $json.expected_amount
        },
        last_payment_receipt_submission: {
          submitted_at: new Date().toISOString(),
          decision: $json.decision,
          detected_amount: $json.detected_amount,
          expected_amount: $json.expected_amount
        }
      }
    }
  }
];

const current = $json.context_json || {};

return [
  {
    json: {
      ...$json,
      new_context_json: {
        ...current,
        flow: 'delivery',
        step: 'awaiting_payment_validation',
        last_pending_payment_order: {
          ...(current.last_pending_payment_order || {}),
          order_id: $json.order_id,
          order_status: 'paid_pending_confirmation',
          total_amount: $json.expected_amount
        },
        last_payment_receipt_submission: {
          submitted_at: new Date().toISOString(),
          decision: $json.decision,
          detected_amount: $json.detected_amount,
          expected_amount: $json.expected_amount,
          payment_receipt_id: $json.payment_receipt_id ?? null
        }
      }
    }
  }
];

const input = $input.first().json || {};
const ctx = input.context_json || {};

return [
  {
    json: {
      ...input,
      reply_text: 'No pude procesar correctamente la imagen. Por favor vuelve a enviar una captura clara del voucher.',
      new_flow: 'delivery',
      new_step: 'awaiting_payment',
      context_json: {
        ...ctx,
        flow: 'delivery',
        step: 'awaiting_payment'
      }
    }
  }
];

const current = $json.context_json || {};

return [
  {
    json: {
      ...$json,
      new_context_json: {
        ...current,
        flow: 'delivery',
        step: 'awaiting_payment',
        last_pending_payment_order: {
          ...(current.last_pending_payment_order || {}),
          order_id: $json.order_id,
          order_status: 'pending_payment',
          total_amount: $json.expected_amount
        },
        last_payment_receipt_submission: {
          submitted_at: new Date().toISOString(),
          decision: $json.decision,
          detected_amount: $json.detected_amount,
          expected_amount: $json.expected_amount,
          payment_receipt_id: $json.payment_receipt_id ?? null
        }
      }
    }
  }
];

const input = $input.first().json || {};
const blockingOrder = input.blocking_order || {};

const total =
  blockingOrder.total_amount === null || blockingOrder.total_amount === undefined
    ? null
    : Number(blockingOrder.total_amount);

const reply =
  total !== null
    ? `Tienes un pedido pendiente de pago por S/ ${total.toFixed(2)}. Por favor envíame la captura o voucher de pago para validarlo.`
    : 'Tienes un pedido pendiente de pago. Por favor envíame la captura o voucher de pago para validarlo.';

return [
  {
    json: {
      ...input,
      reply_text: reply,
      new_flow: 'delivery',
      new_step: 'awaiting_payment',
      context_json: {
        ...(input.context_json || {}),
        flow: 'delivery',
        step: 'awaiting_payment'
      }
    }
  }
];

const input = $input.first().json || {};
const blockingOrder = input.blocking_order || {};

const total =
  blockingOrder.total_amount === null || blockingOrder.total_amount === undefined
    ? null
    : Number(blockingOrder.total_amount);

const reply =
  total !== null
    ? `Recibimos tu voucher para el pedido por S/ ${total.toFixed(2)} y estamos verificando el pago. En cuanto quede validado, tu pedido pasará a preparación.`
    : 'Recibimos tu voucher y estamos verificando el pago. En cuanto quede validado, tu pedido pasará a preparación.';

return [
  {
    json: {
      ...input,
      reply_text: reply,
      new_flow: 'delivery',
      new_step: 'awaiting_payment_validation',
      context_json: {
        ...(input.context_json || {}),
        flow: 'delivery',
        step: 'awaiting_payment_validation'
      }
    }
  }
];
